#!/bin/sh
# Runs before SillyTavern on first boot.
# Writes a minimal config.yaml if none exists yet.
# ST will add all missing config values itself on startup.

CONFIG="/home/node/app/config/config.yaml"

if [ ! -f "$CONFIG" ]; then
  echo "[st-init] Writing base config.yaml..."
  cat > "$CONFIG" <<'EOF'
# Auto-generated by st-init.sh on first boot.
# SillyTavern will add remaining defaults on startup.

# whitelistMode: true satisfies ST's startup security check.
# ST runs in the frontend container's network namespace, so nginx
# connects to localhost:8000 — ST always sees 127.0.0.1, which is
# whitelisted. Port 8000 is never exposed externally.
whitelistMode: true
enableForwardedWhitelist: false
enableUserAccounts: true
listen: true
whitelist:
  - 127.0.0.1
EOF
fi

# Explicitly set enableForwardedWhitelist: false.
# When true, ST checks X-Forwarded-For / X-Real-IP against the whitelist,
# blocking external clients even though nginx pins X-Forwarded-For to 127.0.0.1.
# With false, ST only checks the direct connection IP (always 127.0.0.1 from nginx).
if grep -q 'enableForwardedWhitelist' "$CONFIG"; then
  sed -i 's/enableForwardedWhitelist:.*/enableForwardedWhitelist: false/' "$CONFIG"
else
  echo 'enableForwardedWhitelist: false' >> "$CONFIG"
fi

# ST rewrites config.yaml during startup, overriding our values.
# Run a background patcher that waits for ST to be listening, then
# fixes the config and sends SIGHUP so ST re-reads it.
(
  # Wait for ST to be ready (up to 120s)
  for i in $(seq 1 60); do
    wget -q -O /dev/null http://127.0.0.1:${ST_PORT:-8000}/api/ping 2>/dev/null && break
    sleep 2
  done

  CHANGED=0
  if grep -q 'enableForwardedWhitelist: true' "$CONFIG"; then
    sed -i 's/enableForwardedWhitelist: true/enableForwardedWhitelist: false/' "$CONFIG"
    CHANGED=1
  fi
  if grep -q 'whitelistDockerHosts: true' "$CONFIG"; then
    sed -i 's/whitelistDockerHosts: true/whitelistDockerHosts: false/' "$CONFIG"
    CHANGED=1
  fi
  if grep -q 'basicAuthMode: true' "$CONFIG"; then
    sed -i 's/basicAuthMode: true/basicAuthMode: false/' "$CONFIG"
    CHANGED=1
  fi

  if [ "$CHANGED" = "1" ]; then
    echo "[st-init] Patched config.yaml after startup"
    # Restart ST so it picks up the patched config
    kill -HUP 1 2>/dev/null || true
  fi
) &

exec node /home/node/app/server.js "$@"
